<?php
declare(strict_types=1);

/**
 * ═══════════════════════════════════════════════════════════════════
 * Webkernel — Logo Helpers
 * bootstrap/webkernel/config/helpers/logos.php
 * ═══════════════════════════════════════════════════════════════════
 *
 * Helper functions that return company/application logos in base64
 * format (data URI) for Light and Dark modes.
 * ═══════════════════════════════════════════════════════════════════
 */

/**
 * Returns the logo for Light mode.
 *
 * @return string Full data URI (data:image/...)
 */
if (!function_exists('webkernelLogoForLightMode')) {
    function webkernelLogoForLightMode(): string
    {
    return
   'data:image/png;base64,' . '';
    }
}

/**
 * Returns the logo for Dark mode.
 *
 * @return string Full data URI (data:image/...)
 */
if (!function_exists('webkernelLogoForDarkMode')) {
    function webkernelLogoForDarkMode(): string
    {
        return 'data:image/png;base64,' .
               '';
    }
}
